const item = $input.first().json;

return [{
  json: {
    titulo: item.titulo || 'Sin título',
    precio: parseFloat(item.precio) || 0,
    moneda: item.moneda || 'USD',
    url_original: item.link,
    barrio: item.barrio || '',
    imagen_principal: item.fotos && item.fotos.length > 0 ? item.fotos[0] : '',
    imagenes: JSON.stringify(item.fotos || []),
    descripcion: item.descripcion || '',
    tipo_operacion: item.tipo_operacion || 'alquiler',
    es_dueno_directo: !!item.es_dueno_directo,
    fuente: 'meli_hunter_local_pro'
  }
}];

